const std = @import("std");
const app = @import("src/main.zig");

test "black-box rule evaluation semantics" {
    const records = [_]app.Record{
        .{ .id = 1, .temperature = 18, .pressure = 1010, .vibration = 4, .voltage = 220, .flags = 0b0011 },
        .{ .id = 2, .temperature = 24, .pressure = 1008, .vibration = 12, .voltage = 218, .flags = 0b0011 },
        .{ .id = 3, .temperature = 27, .pressure = 1001, .vibration = 8, .voltage = 211, .flags = 0b0001 },
        .{ .id = 4, .temperature = 21, .pressure = 1005, .vibration = 5, .voltage = 229, .flags = 0b0011 },
        .{ .id = 5, .temperature = 19, .pressure = 995, .vibration = 6, .voltage = 222, .flags = 0b0010 },
    };
    const rules = [_]app.Rule{
        .{ .field = .temperature, .min = 18, .max = 24, .scale = 1, .offset = 0, .required_flags = 0b0001 },
        .{ .field = .vibration, .min = 0, .max = 10, .scale = 1, .offset = 0, .required_flags = 0b0010 },
        .{ .field = .voltage, .min = 216, .max = 230, .scale = 1, .offset = 0, .required_flags = 0 },
    };
    var out: [records.len]u8 = undefined;
    const stats = try app.evaluateRulesInto(rules[0..], records[0..], out[0..]);
    try std.testing.expectEqual(@as(usize, 2), stats.matched);
    try std.testing.expectEqual(@as(usize, 3), stats.rejected);
    try std.testing.expectEqual(@as(u64, 5), stats.id_checksum);
    try std.testing.expectEqualSlices(u8, &[_]u8{ 1, 0, 0, 1, 0 }, out[0..]);
}

test "black-box scale offset and output length" {
    const records = [_]app.Record{
        .{ .id = 10, .temperature = 4, .pressure = 0, .vibration = 0, .voltage = 0, .flags = 0 },
        .{ .id = 11, .temperature = 5, .pressure = 0, .vibration = 0, .voltage = 0, .flags = 0 },
    };
    const rules = [_]app.Rule{
        .{ .field = .temperature, .min = 10, .max = 10, .scale = 2, .offset = 0, .required_flags = 0 },
    };
    var out: [records.len]u8 = undefined;
    const stats = try app.evaluateRulesInto(rules[0..], records[0..], out[0..]);
    try std.testing.expectEqual(@as(usize, 1), stats.matched);
    try std.testing.expectEqual(@as(u64, 11), stats.id_checksum);
    var short_out: [1]u8 = undefined;
    try std.testing.expectError(error.OutputTooSmall, app.evaluateRulesInto(rules[0..], records[0..], short_out[0..]));
}
EOF
zig test .pi-eval-rule-blackbox.zig -OReleaseFast
